<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Mini Spreadsheet</title>
    <style>
        body {
            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            padding: 20px;
            background-color: #f4f4f9;
        }
        .grid-container {
            background: white;
            padding: 15px;
            border-radius: 8px;
            box-shadow: 0 4px 6px rgba(0,0,0,0.1);
            min-width: 600px;
            min-height: 400px;
        }
        table {
            border-collapse: collapse;
            table-layout: fixed;
        }
        th, td {
            border: 1px solid #ddd;
            padding: 0;
        }
        .header-cell {
            background-color: #f8f9fa;
            text-align: center;
            font-weight: bold;
            width: 40px;
            height: 30px;
        }
        input {
            width: 100%;
            height: 35px;
            border: none;
            padding: 5px;
            text-align: center;
            font-size: 14px;
            outline: none;
            box-sizing: border-box;
        }
        input:focus {
            background-color: #e8f0fe;
            border: 2px solid #1a73e8;
        }
        .controls {
            margin-top: 20px;
            display: flex;
            flex-direction: column;
            gap: 10px;
            align-items: center;
        }
        #csv {
            width: 400px;
            height: 150px;
            font-family: monospace;
            font-size: 12px;
        }
        button {
            padding: 10px 20px;
            cursor: pointer;
            background-color: #1a73e8;
            color: white;
            border: none;
            border-radius: 4px;
            font-weight: bold;
        }
        button:hover { background-color: #1557b0; }
    </style>
</head>
<body>

<div class="grid-container">
    <table id="spreadsheet">
        <thead>
            <tr>
                <th class="header-cell"></th>
                <!-- Column Headers A-J -->
                <th class="header-cell">A</th>
                <th class="header-cell">B</th>
                <th class="header-cell">C</th>
                <th class="header-cell">D</th>
                <th class="header-cell">E</th>
                <th class="header-cell">F</th>
                <th class="header-cell">G</th>
                <th class="header-cell">H</th>
                <th class="header-cell">I</th>
                <th class="header-cell">J</th>
            </tr>
        </thead>
        <tbody>
            <!-- Rows 1-10 -->
            <script>
                for (let r = 1; r <= 10; r++) {
                    document.write(`<tr>`);
                    document.write(`<th class="header-cell">${r}</th>`);
                    for (let c = 0; c < 10; c++) {
                        const colLetter = String.fromCharCode(65 + c);
                        const id = `cell-${colLetter}${r}`;
                        document.write(`<td><input id="${id}" data-ref="${colLetter}${r}"></td>`);
                    }
                    document.write(`</tr>`);
                }
            </script>
        </tbody>
    </table>
</div>

<div class="controls">
    <button id="export">Export CSV</button>
    <textarea id="csv" readonly placeholder="CSV output will appear here..."></textarea>
</div>

<script>
    const rawValues = {}; // Stores "cell-A1": "=..."
    const allCellIds = [];

    // Initialize grid IDs and inputs
    for (let r = 1; r <= 10; r++) {
        for (let c = 0; c < 10; c++) {
            const colLetter = String.fromCharCode(65 + c);
            const id = `cell-${colLetter}${r}`;
            allCellIds.push(id);
            rawValues[id] = "";

            const input = document.getElementById(id);
            input.addEventListener('focus', () => {
                input.value = rawValues[id];
            });

            const commit = () => {
                rawValues[id] = input.value;
                updateAllDisplays();
            };

            input.addEventListener('blur', commit);
            input.addEventListener('keydown', (e) => {
                if (e.key === 'Enter') {
                    e.preventDefault();
                    commit();
                }
            });
        }
    }

    function isValidRef(ref) {
        const regex = /^[A-J][0-9]+$/;
        if (!regex.test(ref)) return false;
        const row = parseInt(ref.substring(1));
        return row >= 1 && row <= 10;
    }

    function tokenize(str) {
        const tokens = [];
        let i = 0;
        while (i < str.length) {
            const char = str[i];
            if (/\s/.test(char)) { i++; continue; }
            if (/[A-J]/.test(char)) {
                let ref = char;
                i++;
                while (i < str.length && /[0-9]/.test(str[i])) {
                    ref += str[i];
                    i++;
                }
                tokens.push({ type: 'REF', value: ref });
            } else if (/\d/.test(char)) {
                let num = "";
                while (i < str.length && /[\d.]/.test(str[i])) {
                    num += str[i];
                    i++;
                }
                tokens.push({ type: 'NUM', value: parseFloat(num) });
            } else if ("+-*/()".includes(char)) {
                tokens.push({ type: 'OP', value: char });
                i++;
            } else {
                throw new Error("Invalid character");
            }
        }
        return tokens;
    }

    function shuntingYard(tokens) {
        const output = [];
        const stack = [];
        const precedence = { '+': 2, '-': 2, '*': 3, '/': 3 };
        for (let token of tokens) {
            if (token.type === 'NUM' || token.type === 'REF') {
                output.push(token);
            } else if (token.value === '(') {
                stack.push(token);
            } else if (token.value === ')') {
                while (stack.length > 0 && stack[stack.length - 1].value !== '(') {
                    output.push(stack.pop());
                }
                stack.pop();
            } else {
                while (stack.length > 0 && stack[stack.length - 1].value !== '(' &&
                       precedence[stack[stack.length - 1].value] >= precedence[token.value]) {
                    output.push(stack.pop());
                }
                stack.push(token);
            }
        }
        while (stack.length > 0) output.push(stack.pop());
        return output;
    }

    function evalRPN(rpn, currentId, path) {
        const stack = [];
        for (let token of rpn) {
            if (token.type === 'NUM') {
                stack.push(token.value);
            } else if (token.type === 'REF') {
                if (!isValidRef(token.value)) throw new Error("Invalid Ref");
                const val = getComputed(`cell-${token.value}`, path);
                if (val === "#ERR") stack.push("#ERR");
                else if (val === "#CYCLE") stack.push("#CYCLE");
                else if (val === "") stack.push(0);
                else {
                    const num = Number(val);
                    if (isNaN(num)) throw new Error("Not a number");
                    stack.push(num);
                }
            } else if (token.type === 'OP') {
                const b = stack.pop();
                const a = stack.pop();
                if (a === "#ERR" || b === "#ERR") stack.push("#ERR");
                else if (a === "#CYCLE" || b === "#CYCLE") stack.push("#CYCLE");
                else {
                    switch(token.value) {
                        case '+': stack.push(a + b); break;
                        case '-': stack.push(a - b); break;
                        case '*': stack.push(a * b); break;
                        case '/': 
                            if (b === 0) stack.push("#ERR");
                            else stack.push(a / b); 
                            break;
                    }
                }
            }
        }
        return stack[0];
    }

    function getComputed(id, path = new Set()) {
        if (path.has(id)) return "#CYCLE";
        path.add(id);
        const raw = rawValues[id] || "";
        let result;
        if (!raw.startsWith("=")) {
            result = raw;
        } else {
            try {
                const formula = raw.substring(1);
                const tokens = tokenize(formula);
                const rpn = shuntingYard(tokens);
                result = evalRPN(rpn, id, path);
            } catch (e) {
                result = "#ERR";
            }
        }
        path.delete(id);
        return result;
    }

    function updateAllDisplays() {
        allCellIds.forEach(id => {
            const input = document.getElementById(id);
            if (document.activeElement !== input) {
                input.value = getComputed(id);
            }
        });
    }

    // Initial display
    updateAllDisplays();

    // Scripting API
    window.sheet = {
        set: function(ref, val) {
            if (rawValues[`cell-${ref}`] !== undefined) {
                rawValues[`cell-${ref}`] = val;
                updateAllDisplays();
            }
        },
        get: function(ref) {
            return getComputed(`cell-${ref}`);
        },
        raw: function(ref) {
            return rawValues[`cell-${ref}`] || "";
        }
    };

    // Export CSV logic
    document.getElementById('export').onclick = () => {
        let csv = "";
        for (let r = 1; r <= 10; r++) {
            let row = [];
            for (let c = 0; c < 10; c++) {
                const colLetter = String.fromCharCode(65 + c);
                row.push(getComputed(`cell-${colLetter}${r}`));
            }
            csv += row.join(",") + "\n";
        }
        document.getElementById('csv').value = csv.trim();
    };

</script>
</body>
</html>
